class Solution {
public:
    vector<int> validSequence(string word1, string word2) {
        int m = word1.size(), n = word2.size();
        vector<int> res;
        int diff = 0;
        for (int i = 0, j = 0; i < m && j < n; i++) {
            if (word1[i] == word2[j]) {
                res.push_back(i);
                j++;
            } else {
                diff++;
                if (diff > 1) break;
            }
        }
        if (j != n || diff > 1) return {};
        return res;
    }
};
